// 變數宣告範例 (TON計時器實例通常在FB的VAR_STAT或DB中宣告)
// VAR_INPUT
//    Start_Timer : BOOL; // 計時器啟動輸入
//    Preset_Time : TIME; // 預設延時時間 (例如: T#5S, T#100MS)
// END_VAR
// VAR_OUTPUT
//    Timer_Done : BOOL; // 計時完成輸出
//    Elapsed_Time : TIME; // 當前已計時時間
// END_VAR
// VAR_STAT
//    TON_Instance : TON; // TON計時器實例，必須是靜態或DB變數以保持狀態
// END_VAR

// 呼叫TON計時器功能塊
TON_Instance(IN := Start_Timer, PT := Preset_Time);

// 將計時器輸出賦值給外部變數
Timer_Done := TON_Instance.Q; // Q為計時完成輸出，當計時達到PT時為TRUE
Elapsed_Time := TON_Instance.ET; // ET為當前已計時時間
```

