```scl
// 變數宣告範例
// VAR_INPUT
//    Start_Button : BOOL; // 啟動按鈕 (常開接點)
//    Stop_Button : BOOL; // 停止按鈕 (常閉接點)
// END_VAR
// VAR_OUTPUT
//    Motor_Output : BOOL; // 馬達運行輸出
// END_VAR
// VAR_TEMP
//    Motor_Latching : BOOL; // 內部自保持狀態變數
// END_VAR

// 實現馬達啟停邏輯 (自保持電路)
// 邏輯說明：
// 1. 當Start_Button為TRUE時，嘗試啟動馬達。
// 2. 當Motor_Latching已為TRUE (馬達已運行) 且 Stop_Button未被按下時，保持馬達運行。
// 3. 當Stop_Button被按下 (為FALSE) 時，強制停止馬達。
Motor_Latching := (Start_Button OR Motor_Latching) AND Stop_Button;

// 將自保持狀態賦值給馬達實際輸出
Motor_Output := Motor_Latching;
```

