// 變數宣告範例
// VAR_INPUT
//    Value1 : INT; // 輸入整數值1
//    Value2 : INT; // 輸入整數值2
//    Threshold : INT; // 比較閾值
// END_VAR
// VAR_OUTPUT
//    Result_Exceeds_Threshold : BOOL; // 結果是否超過閾值
// END_VAR
// VAR_TEMP
//    Sum_Value : INT; // 兩數之和的暫存變數
// END_VAR

// 執行算術運算：計算Value1和Value2的和
Sum_Value := Value1 + Value2;

// 執行條件比較：如果和超過閾值，設定輸出為TRUE
IF Sum_Value > Threshold THEN
    Result_Exceeds_Threshold := TRUE;
ELSE
    Result_Exceeds_Threshold := FALSE;
END_IF;

// 也可以使用更簡潔的寫法：
// Result_Exceeds_Threshold := (Sum_Value > Threshold);
